section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-authentication.json",
  "title": "API Authentication",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "mechanism",
    "token_ttl_minutes",
    "refresh_rotation",
    "allowed_algorithms",
    "claims_validated",
    "storage",
    "negative_tests",
    "rotation_plan",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "mechanism": {
      "type": "string",
      "description": "api-key|jwt-bearer|oauth2-code-pkce|mtls|hybrid",
      "minLength": 1
    },
    "token_ttl_minutes": {
      "type": "integer",
      "description": "access token TTL; conventionally 5-15 for JWT"
    },
    "refresh_rotation": {
      "type": "boolean",
      "description": "true when refresh tokens rotate on every use"
    },
    "allowed_algorithms": {
      "type": "array",
      "description": "explicit allowlist (no alg:none); e.g. [RS256, EdDSA]",
      "minItems": 1
    },
    "claims_validated": {
      "type": "array",
      "description": "subset of [iss, aud, exp, nbf, kid] \u2014 all five required in production",
      "minItems": 1
    },
    "storage": {
      "type": "string",
      "description": "cookie-httponly|authorization-header|other (mobile)",
      "minLength": 1
    },
    "negative_tests": {
      "type": "array",
      "description": "list of test ids covering expired, wrong-aud, missing-scope, alg-none",
      "minItems": 1
    },
    "rotation_plan": {
      "type": "string",
      "description": "two-key window policy + cadence",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
